// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract FeeToken {
    string public name = "Fee Token";
    string public symbol = "FEE";
    uint8 public decimals = 18;
    uint256 public totalSupply;
    uint256 public constant MAX_SUPPLY = 1_000_000 * 10 ** 18;
    address public treasury;
    address public owner;

    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    constructor(address _treasury) {
        treasury = _treasury;
        owner = msg.sender;
        uint256 initial = 500_000 * 10 ** 18;
        totalSupply = initial;
        balanceOf[msg.sender] = initial;
        emit Transfer(address(0), msg.sender, initial);
    }

    function transfer(address to, uint256 amount) external returns (bool) {
        return _transfer(msg.sender, to, amount);
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        allowance[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        require(allowance[from][msg.sender] >= amount, "Insufficient allowance");
        allowance[from][msg.sender] -= amount;
        return _transfer(from, to, amount);
    }

    function mint(address to, uint256 amount) external {
        require(msg.sender == owner, "Not owner");
        require(totalSupply + amount <= MAX_SUPPLY, "Exceeds cap");
        totalSupply += amount;
        balanceOf[to] += amount;
        emit Transfer(address(0), to, amount);
    }

    function _transfer(address from, address to, uint256 amount) internal returns (bool) {
        require(balanceOf[from] >= amount, "Insufficient balance");
        uint256 fee = amount / 100; // 1%
        uint256 netAmount = amount - fee;
        balanceOf[from] -= amount;
        balanceOf[to] += netAmount;
        balanceOf[treasury] += fee;
        emit Transfer(from, to, netAmount);
        emit Transfer(from, treasury, fee);
        return true;
    }
}

