// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract WhitelistNFT is ERC721, Ownable {
    uint256 private _nextTokenId;
    uint256 public constant MAX_SUPPLY = 5000;
    uint256 public constant WL_PRICE = 0.03 ether;
    uint256 public constant PUBLIC_PRICE = 0.06 ether;

    enum SalePhase { Closed, Whitelist, Public }
    SalePhase public phase = SalePhase.Closed;

    mapping(address => bool) public whitelist;
    mapping(address => uint256) public whitelistMinted;
    uint256 public constant WL_MAX_PER_WALLET = 2;

    constructor(address initialOwner)
        ERC721("Whitelist NFT", "WNFT")
        Ownable(initialOwner)
    {}

    function setPhase(SalePhase _phase) external onlyOwner {
        phase = _phase;
    }

    function addToWhitelist(address[] calldata addrs) external onlyOwner {
        for (uint256 i = 0; i < addrs.length; i++) {
            whitelist[addrs[i]] = true;
        }
    }

    function whitelistMint(uint256 qty) external payable {
        require(phase == SalePhase.Whitelist, "WL not active");
        require(whitelist[msg.sender], "Not whitelisted");
        require(whitelistMinted[msg.sender] + qty <= WL_MAX_PER_WALLET, "Exceeds WL limit");
        require(_nextTokenId + qty <= MAX_SUPPLY, "Exceeds supply");
        require(msg.value >= WL_PRICE * qty, "Insufficient payment");

        whitelistMinted[msg.sender] += qty;
        for (uint256 i = 0; i < qty; i++) {
            _safeMint(msg.sender, _nextTokenId++);
        }
    }

    function publicMint(uint256 qty) external payable {
        require(phase == SalePhase.Public, "Public sale not active");
        require(qty > 0 && qty <= 5, "1-5 per tx");
        require(_nextTokenId + qty <= MAX_SUPPLY, "Exceeds supply");
        require(msg.value >= PUBLIC_PRICE * qty, "Insufficient payment");

        for (uint256 i = 0; i < qty; i++) {
            _safeMint(msg.sender, _nextTokenId++);
        }
    }

    function withdraw() external onlyOwner {
        payable(owner()).transfer(address(this).balance);
    }
}

