// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract FeeVault {
    uint256 public totalShares;
    uint256 public totalAssets;
    mapping(address => uint256) public shares;

    uint256 public constant DEPOSIT_FEE_BPS = 50;
    uint256 public constant BPS_DENOMINATOR = 10_000;

    function deposit(uint256 assets) external {
        uint256 fee = (assets * DEPOSIT_FEE_BPS) / BPS_DENOMINATOR;
        uint256 netAssets = assets - fee;

        uint256 sharesToMint;
        if (totalShares == 0) {
            sharesToMint = netAssets;
        } else {
            sharesToMint = (netAssets * totalShares) / totalAssets;
        }

        shares[msg.sender] += sharesToMint;
        totalShares += sharesToMint;
        totalAssets += assets; // Full amount goes into vault, fee benefits existing holders
    }

    function redeem(uint256 _shares) external {
        require(shares[msg.sender] >= _shares, "Insufficient shares");
        uint256 assetsToReturn = (_shares * totalAssets) / totalShares;
        shares[msg.sender] -= _shares;
        totalShares -= _shares;
        totalAssets -= assetsToReturn;
    }
}
